const topic = $.input.topic;
const tone = $.input.tone || 'professional';
const wordCount = $.input.wordCount || 1200;
const language = $.input.language || 'English';

const prompt = `You are a professional content writer and WordPress publishing expert. Generate a complete, publish-ready blog article.

TOPIC: ${topic}
TONE: ${tone}
TARGET WORD COUNT: ${wordCount}
LANGUAGE: ${language}

INSTRUCTIONS:
- Write a compelling, well-structured article
- Use proper HTML formatting: <h2>, <h3> for headings, <p> for paragraphs, <ul>/<ol> for lists, <strong>/<em> for emphasis
- Include an engaging introduction that hooks the reader
- Break content into logical sections with descriptive headings
- Include practical examples, tips, or actionable advice
- Write a strong conclusion with a call to action
- Generate an SEO-friendly title
- Create a URL-friendly slug
- Write a meta description under 155 characters
- Suggest relevant tags and categories
- Write a 2-3 sentence excerpt

Return ONLY valid JSON:
{
  "title": "<engaging article title>",
  "slug": "<url-friendly-slug>",
  "content": "<full HTML article body>",
  "excerpt": "<2-3 sentence excerpt>",
  "metaDescription": "<under 155 chars>",
  "tags": ["<tag1>", "<tag2>", "<tag3>", "<tag4>"],
  "categories": ["<category1>"],
  "estimatedWordCount": ${wordCount}
}`;
return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: $.input.topic, slug: $.input.topic.toLowerCase().replace(/[^a-z0-9]+/g, '-').slice(0, 60), content: '<p>' + raw + '</p>', excerpt: $.input.topic, metaDescription: $.input.topic.slice(0, 155), tags: ['blog'], categories: ['Blog'], estimatedWordCount: 0 }; }
